function ProviderIcon(props: { provider: SocialProvider }) {
  if (props.provider === "github") return <GitHubIcon class="size-4" />
  if (props.provider === "google") return <GoogleIcon class="size-4" />

  return <span aria-hidden>{getProviderName(props.provider).slice(0, 1)}</span>
}

export function ProviderButton(props: ProviderButtonProps) {
  const auth = useAuth()
  const [isPending, setIsPending] = createSignal(false)
  const display = () => props.display ?? "full"
  const providerName = () => getProviderName(props.provider)
  const label = () =>
    auth.localization.auth.continueWith.replace("{{provider}}", providerName())
  const signInSocial = async () => {
    if (isPending()) return

    setIsPending(true)

    try {
      await auth.authClient.signIn.social(
        resolveSocialAuthParams({
          provider: props.provider,
          basePaths: auth.basePaths,
          baseURL: auth.baseURL,
          redirectTo: auth.redirectTo,
          view: props.view ?? "signIn",
          viewPaths: auth.viewPaths
        }) as Parameters<typeof auth.authClient.signIn.social>[0]
      )
    } finally {
      setIsPending(false)
    }
  }

  return (
    <Button
      aria-label={providerName()}
      class={props.class}
      disabled={isPending()}
      onClick={signInSocial}
      type="button"
      variant={props.variant ?? "outline"}
    >
      {isPending() ? <Spinner /> : <ProviderIcon provider={props.provider} />}
      {isPending()
        ? null
        : display() === "full"
          ? label()
          : display() === "name"
            ? providerName()
            : null}
    </Button>
  )
}

import type { SocialProvider } from "better-auth/social-providers"

const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/

export type SignInPathInput = {
  identifier: string
  usernameAuth: boolean
}

export type SignInPath =
  | { kind: "email"; email: string }
  | { kind: "username"; username: string }

export type SubmittedSignInInput = {
  formData: FormData
  usernameAuth: boolean
}

export type SubmittedSignIn = {
  password: string
  signInPath: SignInPath
}

export type SocialAuthView = "signIn" | "signUp"

export type SocialAuthURLInput = {
  basePaths: { auth: string }
  baseURL: string
  redirectTo: string
  view: SocialAuthView
  viewPaths: { auth: { signIn: string; signUp: string } }
}

export type SocialAuthURLs = {
  callbackURL: string
  errorCallbackURL: string
  newUserCallbackURL?: string
}

export type SocialAuthParamsInput = SocialAuthURLInput & {
  provider: SocialProvider
}

export type SocialAuthParams = SocialAuthURLs & {
  provider: SocialProvider
}

const getFormValue = (formData: FormData, name: string) => {
  const value = formData.get(name)

  return typeof value === "string" ? value : ""
}

export function resolveSignInPath({
  identifier,
  usernameAuth
}: SignInPathInput): SignInPath {
  const normalizedIdentifier = identifier.trim()

  if (usernameAuth && !emailPattern.test(normalizedIdentifier)) {
    return { kind: "username", username: normalizedIdentifier }
  }

  return { kind: "email", email: normalizedIdentifier }
}

export function resolveSubmittedSignIn({
  formData,
  usernameAuth
}: SubmittedSignInInput): SubmittedSignIn {
  const identifier = usernameAuth
    ? getFormValue(formData, "username")
    : getFormValue(formData, "email")

  return {
    password: getFormValue(formData, "password"),
    signInPath: resolveSignInPath({ identifier, usernameAuth })
  }
}

export function resolveSocialAuthURLs({
  basePaths,
  baseURL,
  redirectTo,
  view,
  viewPaths
}: SocialAuthURLInput): SocialAuthURLs {
  const authViewPath =
    view === "signUp" ? viewPaths.auth.signUp : viewPaths.auth.signIn
  const urls: SocialAuthURLs = {
    callbackURL: `${baseURL}${redirectTo}`,
    errorCallbackURL: `${baseURL}${basePaths.auth}/${authViewPath}`
  }

  if (view === "signUp") {
    urls.newUserCallbackURL = `${baseURL}${redirectTo}`
  }

  return urls
}

export function resolveSocialAuthParams({
  provider,
  ...input
}: SocialAuthParamsInput): SocialAuthParams {
  return {
    provider,
    ...resolveSocialAuthURLs(input)
  }
}

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
